/**
 * Physics Graph Simulation
 * Clean implementation of the obfuscated graph-node physics simulation.
 */

// Math constants used in the original code
const MATH_TAU = 6.283;       // Approx Math.PI * 2
const MATH_PHI = 1.618;       // Golden Ratio
const MATH_SQRT1_2 = 0.707;   // Approx Math.SQRT1_2

// Simulation configuration
const config = {
    repulsionForce: 4000,      // Repulsion strength between nodes (attraction in original)
    defaultSpringCoeff: 0.004, // Default edge spring constant
    damping: 0.92,             // Velocity retention per tick (amplification in original)
    centerGravity: 0.0003,     // Gentle pull towards center (400, 300)
    maxParticles: 40,          // Maximum number of ambient particles (streamSize)
    particleFriction: 0.04,    // Friction coefficient for particles (streamDecay)
    cameraLerp: 0.06           // Interpolation speed for the camera view (theta)
};

// Node Definition
class Node {
    constructor(id, label, radius, x, y) {
        this.id = id;
        this.label = label;
        this.r = radius;
        this.x = x;
        this.y = y;
        this.vx = 0;
        this.vy = 0;
    }
}

// Initialize nodes
const nodes = [
    new Node('hub',     'Hub',     26, 400, 300),
    new Node('alpha',   'Node',    16, 500, 200),
    new Node('beta',    'Node',    16, 300, 400),
    new Node('gamma',   'Node',    14, 250, 180),
    new Node('delta',   'Delta',   14, 550, 380),
    new Node('epsilon', 'Epsilon', 12, 350, 150)
];

// Initialize edges (springs connecting nodes)
const edges = [
    { a: 'hub',   b: 'alpha',   restLength: 160, k: 0.006 },
    { a: 'hub',   b: 'beta',    restLength: 160, k: 0.005 },
    { a: 'hub',   b: 'gamma',   restLength: 170, k: 0.004 },
    { a: 'hub',   b: 'delta',   restLength: 170, k: 0.004 },
    { a: 'hub',   b: 'epsilon', restLength: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',    restLength: 200, k: 0.002 },
    { a: 'gamma', b: 'delta',   restLength: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', restLength: 200, k: 0.002 }
];

// Global State
const view = { x: 400, y: 300, zoom: 1 };
const targetView = { x: 400, y: 300, zoom: 1 };
const particles = [];
let ticks = 0;

// Utility: Find a node by its ID
function getNodeById(id) {
    return nodes.find(node => node.id === id) || null;
}

// Core Physics Step for Graph Nodes
function updateNodes() {
    // 1. Calculate node-to-node repulsion
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            const dx = nodes[i].x - nodes[j].x;
            const dy = nodes[i].y - nodes[j].y;
            const distSq = dx * dx + dy * dy;
            const dist = Math.sqrt(distSq) || 1;

            // Inverse-square law repulsion
            const force = config.repulsionForce / distSq;
            const fx = (dx / dist) * force;
            const fy = (dy / dist) * force;

            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // 2. Calculate edge spring forces
    for (const edge of edges) {
        const n1 = getNodeById(edge.a);
        const n2 = getNodeById(edge.b);
        if (!n1 || !n2) continue;

        const dx = n2.x - n1.x;
        const dy = n2.y - n1.y;
        const dist = Math.sqrt(dx * dx + dy * dy) || 1;

        // Hooke's Law spring calculation
        const stretch = dist - edge.restLength;
        const springForce = (edge.k || config.defaultSpringCoeff) * stretch;

        const fx = (dx / dist) * springForce;
        const fy = (dy / dist) * springForce;

        // Pull nodes towards each other
        n1.vx += fx;
        n1.vy += fy;
        n2.vx -= fx;
        n2.vy -= fy;
    }

    // 3. Apply center gravity, damping, and integrate positions
    for (const node of nodes) {
        // Gently pull towards origin center (400, 300)
        node.vx += (400 - node.x) * config.centerGravity;
        node.vy += (300 - node.y) * config.centerGravity;

        // Apply friction/damping
        node.vx *= config.damping;
        node.vy *= config.damping;

        // Update position based on velocities
        node.x += node.vx;
        node.y += node.vy;
    }
}

// Particle Generation
function spawnParticle() {
    if (particles.length >= config.maxParticles) return;

    // Spawn particle randomly originating from one of the nodes
    const originNode = nodes[Math.floor(Math.random() * nodes.length)];
    const angle = Math.random() * MATH_TAU;
    const speed = 0.3 + Math.random() * MATH_SQRT1_2;

    particles.push({
        x: originNode.x,
        y: originNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + (Math.random() * MATH_PHI) * MATH_SQRT1_2
    });
}

// Particle Physics Step
function updateParticles() {
    const frictionMultiplier = 1 - (config.particleFriction * 0.125); // Evaluates to ~0.995

    // Iterate backwards to safely splice while looping
    for (let i = particles.length - 1; i >= 0; i--) {
        const p = particles[i];
        p.age++;

        // Kill off old particles
        if (p.age > p.maxAge) {
            particles.splice(i, 1);
            continue;
        }

        // Apply dampening to particle speed
        p.vx *= frictionMultiplier;
        p.vy *= frictionMultiplier;

        p.x += p.vx;
        p.y += p.vy;
    }
}

// View / Camera updating
function updateCamera() {
    view.x += (targetView.x - view.x) * config.cameraLerp;
    view.y += (targetView.y - view.y) * config.cameraLerp;
    view.zoom += (targetView.zoom - view.zoom) * config.cameraLerp;
}

// Main Simulation Loop 
function tick() {
    updateNodes();
    updateParticles();
    updateCamera();

    // Spawn a new ambient particle every 3rd tick
    if (ticks % 3 === 0) {
        spawnParticle();
    }

    ticks++;
}

// Start simulation running at 100 FPS (every 10ms)
setInterval(tick, 10);
